def is_Diff(num):
    def digit_sum(n):
        return sum(int(digit) for digit in str(n))

    even_sum = 0
    odd_sum = 0
    for digit in str(num):
        if int(digit) % 2 == 0:
            even_sum += int(digit)
        else:
            odd_sum += int(digit)

    return abs(even_sum - odd_sum) != 0
