def max_Prime_Factors(n):
    def is_prime(num):
        if num < 2:
            return False
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                return False
        return True

    factors = set()
    for i in range(2, n + 1):
        while n % i == 0:
            if is_prime(i):
                factors.add(i)
            n //= i
    return max(factors) if factors else None
```

