def find_Product(nums):
    n = len(nums)
    zero_count = 0
    prod_of_non_zero = 1

    for num in nums:
        if num == 0:
            zero_count += 1
            prod_of_non_zero *= 0
        elif num < 0:
            prod_of_non_zero *= -1
        else:
            prod_of_non_zero *= num

    if zero_count > 1 or prod_of_non_zero == 0:
        return 0
    else:
        return prod_of_non_zero
```

