import heapq

def func(nums, k):
    count = {}
    for num in nums:
        if num not in count:
            count[num] = 1
        else:
            count[num] += 1

    max_heap = []

    for num, freq in count.items():
        heapq.heappush(max_heap, (-freq, num))

        if len(max_heap) > k:
            heapq.heappop(max_heap)

    return [heapq.heappop(max_heap)[1] for _ in range(k)]
```

