def eulerian_num(a, b):
    """
    Calculate Euler's totient function value for a given pair of numbers (a, b).

    Parameters:
    a (int): The first number.
    b (int): The second number.

    Returns:
    int: The result of the Euler's totient function calculation.
    """
    def gcd(a, b):
        while b != 0:
            a, b = b, a % b
        return a

    def euler_totient(n):
        result = n
        p = 2
        while(p * p <= n):
            if (n % p == 0):
                while (n % p == 0):
                    n //= p
                result -= result // p
            p += 1
        if (n > 1):
            result -= result // n
        return result

    return euler_totient(b) * euler_totient(a//gcd(a,b)) // gcd(euler_totient(b),euler_totient(a//gcd(a,b)))
```

