def bell_number(n: int) -> int:
    if n == 0 or n == 1:
        return 1
    elif n == 2:
        return 2
    else:
        b = [0] * (n + 1)
        b[0] = 1
        b[1] = 1
        b[2] = 2
        for i in range(3, n + 1):
            b[i] = sum(b[j] for j in range(i // 2) if i - j >= 0)
        return b[n]
```

