def is_same_patterns(patterns):
    def match(i, j):
        if i == len(patterns[0]):
            return True
        if j == len(patterns):
            return False
        if patterns[i][0] != patterns[j][0]:
            return False
        for k in range(1, min(len(patterns[i]), len(patterns[j])) + 1):
            if match(i + 1, j) and match(i, j + 1) and match(i + 1, j + 1):
                return True
        return False

    return all(match(0, i) for i in range(len(patterns)))
```

