def compute_Last_Digit(a, b):
    def factorial(n):
        if n == 0 or n == 1:
            return 1
        else:
            return n * factorial(n-1)

    fact_a = factorial(a)
    fact_b = factorial(b)

    last_digit = (fact_b // fact_a) % 10

    return last_digit
```

